package datatype;

public class datatype {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		// we here are assigning direct values :
		int age = 21;// accept integer
		double salary = 55000.50;//accept decimal value
		char grade = 'A';//accept character
		String  name = "Tanaya";//accept group of characters 
		 boolean isStudent = true;// accept true  or false
		 
		  //output lines 
// + is used to store the result in that particular (eg. + name)
		 System.out.println("Name:"  +name);// we are taking out/storing  the result in name
         System.out.println("Age:" +age);
         System.out.println("Grade:" +grade);
         System.out.println("Salary:" +salary);
         System.out.println("Student:" +isStudent);
	}

}
